import{_ as a,c as n,o as l,ag as e}from"./chunks/framework.B-XtCDNB.js";const y=JSON.parse('{"title":"Changefeeds (WAL)","description":"","frontmatter":{},"headers":[],"relativePath":"capabilities/changefeeds.md","filePath":"capabilities/changefeeds.md"}'),o={name:"capabilities/changefeeds.md"};function p(t,s,c,r,i,F){return l(),n("div",null,[...s[0]||(s[0]=[e(`<h1 id="changefeeds-wal" tabindex="-1">Changefeeds (WAL) <a class="header-anchor" href="#changefeeds-wal" aria-label="Permalink to &quot;Changefeeds (WAL)&quot;">​</a></h1><p>LinkedQL exposes table-level changefeeds through:</p><div class="language-js"><button title="Copy Code" class="copy"></button><span class="lang">js</span><pre class="shiki material-theme-palenight vp-code" tabindex="0"><code><span class="line"><span style="color:#89DDFF;font-style:italic;">await</span><span style="color:#BABED8;"> db</span><span style="color:#89DDFF;">.</span><span style="color:#BABED8;">wal</span><span style="color:#89DDFF;">.</span><span style="color:#82AAFF;">subscribe</span><span style="color:#BABED8;">(</span><span style="color:#89DDFF;">...</span><span style="color:#BABED8;">)</span></span></code></pre></div><p>This API lets you observe structured commits instead of observing a query result.</p><p>That distinction matters:</p><ul><li>live queries answer &quot;what does this query look like now?&quot;</li><li>changefeeds answer &quot;what table mutations just happened?&quot;</li></ul><h2 id="the-minimal-form" tabindex="-1">The minimal form <a class="header-anchor" href="#the-minimal-form" aria-label="Permalink to &quot;The minimal form&quot;">​</a></h2><div class="language-js"><button title="Copy Code" class="copy"></button><span class="lang">js</span><pre class="shiki material-theme-palenight vp-code" tabindex="0"><code><span class="line"><span style="color:#C792EA;">const</span><span style="color:#BABED8;"> unsubscribe </span><span style="color:#89DDFF;">=</span><span style="color:#89DDFF;font-style:italic;"> await</span><span style="color:#BABED8;"> db</span><span style="color:#89DDFF;">.</span><span style="color:#BABED8;">wal</span><span style="color:#89DDFF;">.</span><span style="color:#82AAFF;">subscribe</span><span style="color:#BABED8;">(</span><span style="color:#89DDFF;">(</span><span style="color:#BABED8;font-style:italic;">commit</span><span style="color:#89DDFF;">)</span><span style="color:#C792EA;"> =&gt;</span><span style="color:#89DDFF;"> {</span></span>
<span class="line"><span style="color:#BABED8;">  console</span><span style="color:#89DDFF;">.</span><span style="color:#82AAFF;">log</span><span style="color:#F07178;">(</span><span style="color:#BABED8;">commit</span><span style="color:#F07178;">)</span><span style="color:#89DDFF;">;</span></span>
<span class="line"><span style="color:#89DDFF;">}</span><span style="color:#BABED8;">)</span><span style="color:#89DDFF;">;</span></span></code></pre></div><p>This subscribes to all matching commits the runtime can produce.</p><h2 id="filtering-by-selector" tabindex="-1">Filtering by selector <a class="header-anchor" href="#filtering-by-selector" aria-label="Permalink to &quot;Filtering by selector&quot;">​</a></h2><p>Most real use cases want to narrow the scope.</p><div class="language-js"><button title="Copy Code" class="copy"></button><span class="lang">js</span><pre class="shiki material-theme-palenight vp-code" tabindex="0"><code><span class="line"><span style="color:#C792EA;">const</span><span style="color:#BABED8;"> unsubscribe </span><span style="color:#89DDFF;">=</span><span style="color:#89DDFF;font-style:italic;"> await</span><span style="color:#BABED8;"> db</span><span style="color:#89DDFF;">.</span><span style="color:#BABED8;">wal</span><span style="color:#89DDFF;">.</span><span style="color:#82AAFF;">subscribe</span><span style="color:#BABED8;">(</span></span>
<span class="line"><span style="color:#89DDFF;">  {</span><span style="color:#F07178;"> public</span><span style="color:#89DDFF;">:</span><span style="color:#BABED8;"> [</span><span style="color:#89DDFF;">&#39;</span><span style="color:#C3E88D;">users</span><span style="color:#89DDFF;">&#39;</span><span style="color:#89DDFF;">,</span><span style="color:#89DDFF;"> &#39;</span><span style="color:#C3E88D;">orders</span><span style="color:#89DDFF;">&#39;</span><span style="color:#BABED8;">] </span><span style="color:#89DDFF;">},</span></span>
<span class="line"><span style="color:#89DDFF;">  (</span><span style="color:#BABED8;font-style:italic;">commit</span><span style="color:#89DDFF;">)</span><span style="color:#C792EA;"> =&gt;</span><span style="color:#89DDFF;"> {</span></span>
<span class="line"><span style="color:#BABED8;">    console</span><span style="color:#89DDFF;">.</span><span style="color:#82AAFF;">log</span><span style="color:#F07178;">(</span><span style="color:#BABED8;">commit</span><span style="color:#89DDFF;">.</span><span style="color:#BABED8;">entries</span><span style="color:#F07178;">)</span><span style="color:#89DDFF;">;</span></span>
<span class="line"><span style="color:#89DDFF;">  }</span></span>
<span class="line"><span style="color:#BABED8;">)</span><span style="color:#89DDFF;">;</span></span></code></pre></div><h3 id="common-selector-forms" tabindex="-1">Common selector forms <a class="header-anchor" href="#common-selector-forms" aria-label="Permalink to &quot;Common selector forms&quot;">​</a></h3><div class="language-js"><button title="Copy Code" class="copy"></button><span class="lang">js</span><pre class="shiki material-theme-palenight vp-code" tabindex="0"><code><span class="line"><span style="color:#89DDFF;">&#39;</span><span style="color:#C3E88D;">*</span><span style="color:#89DDFF;">&#39;</span></span>
<span class="line"><span style="color:#89DDFF;">{</span><span style="color:#FFCB6B;"> public</span><span style="color:#89DDFF;">:</span><span style="color:#F07178;"> [</span><span style="color:#89DDFF;">&#39;</span><span style="color:#C3E88D;">users</span><span style="color:#89DDFF;">&#39;</span><span style="color:#F07178;">] </span><span style="color:#89DDFF;">}</span></span>
<span class="line"><span style="color:#89DDFF;">{</span><span style="color:#FFCB6B;"> public</span><span style="color:#89DDFF;">:</span><span style="color:#F07178;"> [</span><span style="color:#89DDFF;">&#39;</span><span style="color:#C3E88D;">users</span><span style="color:#89DDFF;">&#39;</span><span style="color:#89DDFF;">,</span><span style="color:#89DDFF;"> &#39;</span><span style="color:#C3E88D;">orders</span><span style="color:#89DDFF;">&#39;</span><span style="color:#F07178;">] </span><span style="color:#89DDFF;">}</span></span>
<span class="line"><span style="color:#BABED8;">[</span><span style="color:#89DDFF;">{</span><span style="color:#F07178;"> namespace</span><span style="color:#89DDFF;">:</span><span style="color:#89DDFF;"> &#39;</span><span style="color:#C3E88D;">public</span><span style="color:#89DDFF;">&#39;</span><span style="color:#89DDFF;">,</span><span style="color:#F07178;"> name</span><span style="color:#89DDFF;">:</span><span style="color:#89DDFF;"> &#39;</span><span style="color:#C3E88D;">users</span><span style="color:#89DDFF;">&#39;</span><span style="color:#89DDFF;"> }</span><span style="color:#BABED8;">]</span></span></code></pre></div><p>The selector is normalized internally into a namespace-to-table mapping.</p><h2 id="what-commit-objects-look-like" tabindex="-1">What commit objects look like <a class="header-anchor" href="#what-commit-objects-look-like" aria-label="Permalink to &quot;What commit objects look like&quot;">​</a></h2><p>A commit contains one or more entries describing row-level changes.</p><p>Typical entries look like this:</p><div class="language-js"><button title="Copy Code" class="copy"></button><span class="lang">js</span><pre class="shiki material-theme-palenight vp-code" tabindex="0"><code><span class="line"><span style="color:#89DDFF;">{</span></span>
<span class="line"><span style="color:#FFCB6B;">  op</span><span style="color:#89DDFF;">:</span><span style="color:#89DDFF;"> &#39;</span><span style="color:#C3E88D;">insert</span><span style="color:#89DDFF;">&#39;</span><span style="color:#89DDFF;">,</span></span>
<span class="line"><span style="color:#FFCB6B;">  relation</span><span style="color:#89DDFF;">:</span><span style="color:#89DDFF;"> {</span><span style="color:#FFCB6B;"> namespace</span><span style="color:#89DDFF;">:</span><span style="color:#89DDFF;"> &#39;</span><span style="color:#C3E88D;">public</span><span style="color:#89DDFF;">&#39;</span><span style="color:#89DDFF;">,</span><span style="color:#FFCB6B;"> name</span><span style="color:#89DDFF;">:</span><span style="color:#89DDFF;"> &#39;</span><span style="color:#C3E88D;">users</span><span style="color:#89DDFF;">&#39;</span><span style="color:#89DDFF;"> },</span></span>
<span class="line"><span style="color:#FFCB6B;">  new</span><span style="color:#89DDFF;">:</span><span style="color:#89DDFF;"> {</span><span style="color:#FFCB6B;"> id</span><span style="color:#89DDFF;">:</span><span style="color:#F78C6C;"> 1</span><span style="color:#89DDFF;">,</span><span style="color:#FFCB6B;"> name</span><span style="color:#89DDFF;">:</span><span style="color:#89DDFF;"> &#39;</span><span style="color:#C3E88D;">Ada</span><span style="color:#89DDFF;">&#39;</span><span style="color:#89DDFF;"> }</span></span>
<span class="line"><span style="color:#89DDFF;">}</span></span></code></pre></div><p>Or:</p><div class="language-js"><button title="Copy Code" class="copy"></button><span class="lang">js</span><pre class="shiki material-theme-palenight vp-code" tabindex="0"><code><span class="line"><span style="color:#89DDFF;">{</span></span>
<span class="line"><span style="color:#FFCB6B;">  op</span><span style="color:#89DDFF;">:</span><span style="color:#89DDFF;"> &#39;</span><span style="color:#C3E88D;">update</span><span style="color:#89DDFF;">&#39;</span><span style="color:#89DDFF;">,</span></span>
<span class="line"><span style="color:#FFCB6B;">  relation</span><span style="color:#89DDFF;">:</span><span style="color:#89DDFF;"> {</span><span style="color:#FFCB6B;"> namespace</span><span style="color:#89DDFF;">:</span><span style="color:#89DDFF;"> &#39;</span><span style="color:#C3E88D;">public</span><span style="color:#89DDFF;">&#39;</span><span style="color:#89DDFF;">,</span><span style="color:#FFCB6B;"> name</span><span style="color:#89DDFF;">:</span><span style="color:#89DDFF;"> &#39;</span><span style="color:#C3E88D;">users</span><span style="color:#89DDFF;">&#39;</span><span style="color:#89DDFF;"> },</span></span>
<span class="line"><span style="color:#FFCB6B;">  old</span><span style="color:#89DDFF;">:</span><span style="color:#89DDFF;"> {</span><span style="color:#FFCB6B;"> id</span><span style="color:#89DDFF;">:</span><span style="color:#F78C6C;"> 1</span><span style="color:#89DDFF;">,</span><span style="color:#FFCB6B;"> name</span><span style="color:#89DDFF;">:</span><span style="color:#89DDFF;"> &#39;</span><span style="color:#C3E88D;">Ada</span><span style="color:#89DDFF;">&#39;</span><span style="color:#89DDFF;"> },</span></span>
<span class="line"><span style="color:#FFCB6B;">  new</span><span style="color:#89DDFF;">:</span><span style="color:#89DDFF;"> {</span><span style="color:#FFCB6B;"> id</span><span style="color:#89DDFF;">:</span><span style="color:#F78C6C;"> 1</span><span style="color:#89DDFF;">,</span><span style="color:#FFCB6B;"> name</span><span style="color:#89DDFF;">:</span><span style="color:#89DDFF;"> &#39;</span><span style="color:#C3E88D;">Ada Lovelace</span><span style="color:#89DDFF;">&#39;</span><span style="color:#89DDFF;"> }</span></span>
<span class="line"><span style="color:#89DDFF;">}</span></span></code></pre></div><p>Or:</p><div class="language-js"><button title="Copy Code" class="copy"></button><span class="lang">js</span><pre class="shiki material-theme-palenight vp-code" tabindex="0"><code><span class="line"><span style="color:#89DDFF;">{</span></span>
<span class="line"><span style="color:#FFCB6B;">  op</span><span style="color:#89DDFF;">:</span><span style="color:#89DDFF;"> &#39;</span><span style="color:#C3E88D;">delete</span><span style="color:#89DDFF;">&#39;</span><span style="color:#89DDFF;">,</span></span>
<span class="line"><span style="color:#FFCB6B;">  relation</span><span style="color:#89DDFF;">:</span><span style="color:#89DDFF;"> {</span><span style="color:#FFCB6B;"> namespace</span><span style="color:#89DDFF;">:</span><span style="color:#89DDFF;"> &#39;</span><span style="color:#C3E88D;">public</span><span style="color:#89DDFF;">&#39;</span><span style="color:#89DDFF;">,</span><span style="color:#FFCB6B;"> name</span><span style="color:#89DDFF;">:</span><span style="color:#89DDFF;"> &#39;</span><span style="color:#C3E88D;">users</span><span style="color:#89DDFF;">&#39;</span><span style="color:#89DDFF;"> },</span></span>
<span class="line"><span style="color:#FFCB6B;">  old</span><span style="color:#89DDFF;">:</span><span style="color:#89DDFF;"> {</span><span style="color:#FFCB6B;"> id</span><span style="color:#89DDFF;">:</span><span style="color:#F78C6C;"> 1</span><span style="color:#89DDFF;">,</span><span style="color:#FFCB6B;"> name</span><span style="color:#89DDFF;">:</span><span style="color:#89DDFF;"> &#39;</span><span style="color:#C3E88D;">Ada Lovelace</span><span style="color:#89DDFF;">&#39;</span><span style="color:#89DDFF;"> }</span></span>
<span class="line"><span style="color:#89DDFF;">}</span></span></code></pre></div><p>The exact payload depends on the mutation and runtime, but this is the mental model:</p><ul><li><code>op</code> tells you what happened</li><li><code>relation</code> tells you where it happened</li><li><code>old</code> / <code>new</code> describe the row transition</li></ul><h2 id="example-subscribe-to-all-commits-on-one-table" tabindex="-1">Example: subscribe to all commits on one table <a class="header-anchor" href="#example-subscribe-to-all-commits-on-one-table" aria-label="Permalink to &quot;Example: subscribe to all commits on one table&quot;">​</a></h2><div class="language-js"><button title="Copy Code" class="copy"></button><span class="lang">js</span><pre class="shiki material-theme-palenight vp-code" tabindex="0"><code><span class="line"><span style="color:#C792EA;">const</span><span style="color:#BABED8;"> events </span><span style="color:#89DDFF;">=</span><span style="color:#BABED8;"> []</span><span style="color:#89DDFF;">;</span></span>
<span class="line"></span>
<span class="line"><span style="color:#C792EA;">const</span><span style="color:#BABED8;"> unsubscribe </span><span style="color:#89DDFF;">=</span><span style="color:#89DDFF;font-style:italic;"> await</span><span style="color:#BABED8;"> db</span><span style="color:#89DDFF;">.</span><span style="color:#BABED8;">wal</span><span style="color:#89DDFF;">.</span><span style="color:#82AAFF;">subscribe</span><span style="color:#BABED8;">(</span></span>
<span class="line"><span style="color:#89DDFF;">  {</span><span style="color:#F07178;"> public</span><span style="color:#89DDFF;">:</span><span style="color:#BABED8;"> [</span><span style="color:#89DDFF;">&#39;</span><span style="color:#C3E88D;">users</span><span style="color:#89DDFF;">&#39;</span><span style="color:#BABED8;">] </span><span style="color:#89DDFF;">},</span></span>
<span class="line"><span style="color:#89DDFF;">  (</span><span style="color:#BABED8;font-style:italic;">commit</span><span style="color:#89DDFF;">)</span><span style="color:#C792EA;"> =&gt;</span><span style="color:#BABED8;"> events</span><span style="color:#89DDFF;">.</span><span style="color:#82AAFF;">push</span><span style="color:#BABED8;">(commit)</span></span>
<span class="line"><span style="color:#BABED8;">)</span><span style="color:#89DDFF;">;</span></span>
<span class="line"></span>
<span class="line"><span style="color:#89DDFF;font-style:italic;">await</span><span style="color:#BABED8;"> db</span><span style="color:#89DDFF;">.</span><span style="color:#82AAFF;">query</span><span style="color:#BABED8;">(</span><span style="color:#89DDFF;">\`</span><span style="color:#C3E88D;">INSERT INTO public.users (id, name) VALUES (1, &#39;Ada&#39;)</span><span style="color:#89DDFF;">\`</span><span style="color:#BABED8;">)</span><span style="color:#89DDFF;">;</span></span>
<span class="line"><span style="color:#89DDFF;font-style:italic;">await</span><span style="color:#BABED8;"> db</span><span style="color:#89DDFF;">.</span><span style="color:#82AAFF;">query</span><span style="color:#BABED8;">(</span><span style="color:#89DDFF;">\`</span><span style="color:#C3E88D;">UPDATE public.users SET name = &#39;Ada Lovelace&#39; WHERE id = 1</span><span style="color:#89DDFF;">\`</span><span style="color:#BABED8;">)</span><span style="color:#89DDFF;">;</span></span>
<span class="line"><span style="color:#89DDFF;font-style:italic;">await</span><span style="color:#BABED8;"> db</span><span style="color:#89DDFF;">.</span><span style="color:#82AAFF;">query</span><span style="color:#BABED8;">(</span><span style="color:#89DDFF;">\`</span><span style="color:#C3E88D;">DELETE FROM public.users WHERE id = 1</span><span style="color:#89DDFF;">\`</span><span style="color:#BABED8;">)</span><span style="color:#89DDFF;">;</span></span>
<span class="line"></span>
<span class="line"><span style="color:#89DDFF;font-style:italic;">await</span><span style="color:#82AAFF;"> unsubscribe</span><span style="color:#BABED8;">()</span><span style="color:#89DDFF;">;</span></span></code></pre></div><p>What this gives you:</p><ul><li>insert commit entries</li><li>update commit entries</li><li>delete commit entries</li></ul><h2 id="stable-subscription-ids-and-forgetting-state" tabindex="-1">Stable subscription ids and forgetting state <a class="header-anchor" href="#stable-subscription-ids-and-forgetting-state" aria-label="Permalink to &quot;Stable subscription ids and forgetting state&quot;">​</a></h2><p>Subscriptions can be given a stable id:</p><div class="language-js"><button title="Copy Code" class="copy"></button><span class="lang">js</span><pre class="shiki material-theme-palenight vp-code" tabindex="0"><code><span class="line"><span style="color:#C792EA;">const</span><span style="color:#BABED8;"> unsubscribe </span><span style="color:#89DDFF;">=</span><span style="color:#89DDFF;font-style:italic;"> await</span><span style="color:#BABED8;"> db</span><span style="color:#89DDFF;">.</span><span style="color:#BABED8;">wal</span><span style="color:#89DDFF;">.</span><span style="color:#82AAFF;">subscribe</span><span style="color:#BABED8;">(</span></span>
<span class="line"><span style="color:#89DDFF;">  {</span><span style="color:#F07178;"> public</span><span style="color:#89DDFF;">:</span><span style="color:#BABED8;"> [</span><span style="color:#89DDFF;">&#39;</span><span style="color:#C3E88D;">users</span><span style="color:#89DDFF;">&#39;</span><span style="color:#BABED8;">] </span><span style="color:#89DDFF;">},</span></span>
<span class="line"><span style="color:#89DDFF;">  (</span><span style="color:#BABED8;font-style:italic;">commit</span><span style="color:#89DDFF;">)</span><span style="color:#C792EA;"> =&gt;</span><span style="color:#BABED8;"> console</span><span style="color:#89DDFF;">.</span><span style="color:#82AAFF;">log</span><span style="color:#BABED8;">(commit)</span><span style="color:#89DDFF;">,</span></span>
<span class="line"><span style="color:#89DDFF;">  {</span><span style="color:#F07178;"> id</span><span style="color:#89DDFF;">:</span><span style="color:#89DDFF;"> &#39;</span><span style="color:#C3E88D;">users_slot</span><span style="color:#89DDFF;">&#39;</span><span style="color:#89DDFF;"> }</span></span>
<span class="line"><span style="color:#BABED8;">)</span><span style="color:#89DDFF;">;</span></span></code></pre></div><p>This matters for runtimes that persist subscription slots and catch-up state.</p><p>When you want to remove that persisted slot state too:</p><div class="language-js"><button title="Copy Code" class="copy"></button><span class="lang">js</span><pre class="shiki material-theme-palenight vp-code" tabindex="0"><code><span class="line"><span style="color:#89DDFF;font-style:italic;">await</span><span style="color:#82AAFF;"> unsubscribe</span><span style="color:#BABED8;">(</span><span style="color:#89DDFF;">{</span><span style="color:#F07178;"> forget</span><span style="color:#89DDFF;">:</span><span style="color:#FF9CAC;"> true</span><span style="color:#89DDFF;"> }</span><span style="color:#BABED8;">)</span><span style="color:#89DDFF;">;</span></span></code></pre></div><h2 id="wal-subscriptions-vs-live-queries" tabindex="-1">WAL subscriptions vs live queries <a class="header-anchor" href="#wal-subscriptions-vs-live-queries" aria-label="Permalink to &quot;WAL subscriptions vs live queries&quot;">​</a></h2><p>These two capabilities often appear together, but they serve different jobs.</p><h3 id="use-a-live-query-when" tabindex="-1">Use a live query when <a class="header-anchor" href="#use-a-live-query-when" aria-label="Permalink to &quot;Use a live query when&quot;">​</a></h3><ul><li>your application wants the <em>current result</em> of a query</li><li>you want LinkedQL to maintain that result for you</li><li>the UI is driven by a query-shaped view</li></ul><h3 id="use-wal-subscribe-when" tabindex="-1">Use <code>wal.subscribe()</code> when <a class="header-anchor" href="#use-wal-subscribe-when" aria-label="Permalink to &quot;Use \`wal.subscribe()\` when&quot;">​</a></h3><ul><li>you care about table-level events</li><li>you want to build your own projection or side effects</li><li>you want direct visibility into inserts, updates, and deletes</li></ul><h2 id="runtime-notes" tabindex="-1">Runtime notes <a class="header-anchor" href="#runtime-notes" aria-label="Permalink to &quot;Runtime notes&quot;">​</a></h2><h3 id="flashql" tabindex="-1">FlashQL <a class="header-anchor" href="#flashql" aria-label="Permalink to &quot;FlashQL&quot;">​</a></h3><p>FlashQL has a built-in WAL/changefeed engine. No external replication server is required.</p><p>That makes it especially convenient for:</p><ul><li>local-first apps</li><li>local event processors</li><li>testing change-driven flows</li></ul><h3 id="postgresql" tabindex="-1">PostgreSQL <a class="header-anchor" href="#postgresql" aria-label="Permalink to &quot;PostgreSQL&quot;">​</a></h3><p>With <code>PGClient</code>, WAL-backed capabilities rely on PostgreSQL logical replication setup.</p><h3 id="edgeclient" tabindex="-1">EdgeClient <a class="header-anchor" href="#edgeclient" aria-label="Permalink to &quot;EdgeClient&quot;">​</a></h3><p><code>EdgeClient</code> forwards WAL subscriptions over transport from an upstream LinkedQL-capable runtime such as:</p><ul><li><code>PGClient</code> behind an <code>EdgeWorker</code></li><li><code>FlashQL</code> behind an <code>EdgeWorker</code></li></ul><h2 id="changefeeds-and-sync" tabindex="-1">Changefeeds and sync <a class="header-anchor" href="#changefeeds-and-sync" aria-label="Permalink to &quot;Changefeeds and sync&quot;">​</a></h2><p>FlashQL&#39;s realtime sync views are built on the same general changefeed idea.</p><p>That is worth understanding because it connects two seemingly separate features:</p><ul><li>a table-level subscription is useful directly to applications</li><li>that same mechanism also powers local realtime mirroring in FlashQL sync workflows</li></ul><p>See: <a href="/flashql/sync">FlashQL Sync</a></p><h2 id="related-docs" tabindex="-1">Related docs <a class="header-anchor" href="#related-docs" aria-label="Permalink to &quot;Related docs&quot;">​</a></h2><ul><li><a href="/docs/query-api">Query Interface</a></li><li><a href="/capabilities/live-queries">Live Queries</a></li><li><a href="/engineering/realtime-engine">The Realtime Engine</a></li></ul>`,58)])])}const d=a(o,[["render",p]]);export{y as __pageData,d as default};
